package org.joda.time;

import junit.framework.TestCase;
import org.joda.time.DateTimeFieldType;
import org.joda.time.Partial;

public class ReproductionTest extends TestCase {

    public void testConstructor_YearBeforeEra() {
        DateTimeFieldType[] types = new DateTimeFieldType[] {
            DateTimeFieldType.year(),
            DateTimeFieldType.era(),
            DateTimeFieldType.monthOfYear()
        };
        int[] values = new int[] {2005, 1, 1};

        try {
            new Partial(types, values);
            fail("Constructor should have thrown IllegalArgumentException for Year before Era");
        } catch (IllegalArgumentException ex) {
            // Expected
            String message = ex.getMessage();
            if (message == null || !message.contains("must be in order largest-smallest")) {
                fail("Exception message should indicate order problem, but was: " + message);
            }
        }
    }
}

